def run_project(input_path, output_path):
    lines = load_task_lines(input_path)
    tasks = []
    for line in lines:
        tasks.append(parse_task_line(line))
    summary = build_summary(tasks)
    report = format_report(summary)
    with open(output_path, "w") as file:
        file.write(report)
    return report
